                               .coefIn_251(CoefOutS_251),  /* sfix9_En10 */
                               .coefIn_252(CoefOutS_252),  /* sfix9_En10 */
                               .coefIn_253(CoefOutS_253),  /* sfix9_En10 */
                               .coefIn_254(CoefOutS_254),  /* sfix9_En10 */
                               .coefIn_255(CoefOutS_255),  /* sfix9_En10 */
                               .dinRegVld(dinReg2Vld),
                               .syncReset(syncReset),
                               .dout_1_re(dout_1_M),  /* sfix48_En25 */
                               .doutVld(doutVld_MdeadOut)
                               );

  assign adder_add_cast_2 = {dout_1_M[47], dout_1_M};
  assign adder_add_cast_3 = {dout_1_I[47], dout_1_I};
  assign dout_1_i_1 = adder_add_cast_2 + adder_add_cast_3;

  assign dout_1_cast_i = dout_1_i_1[29:12];

  always_ff @(posedge clk)
    begin : intdelay_8_process
      if (reset == 1'b1) begin
        dout_1_im <= 18'sb000000000000000000;
